import random

def archie_adventures():
    adventures = {
        "riding_hedgehog": "Archie rides a spiky hedgehog to Strict Baptist chapel, singing hymns loudly.",
        "digging_molehills": "Archie digs up molehills, convinced they hide the graves of baby Druids.",
        "chapel_sermon": "During sermon, Archie accidentally sits on a thorny cushion and yelps."
    }
    return random.choice(list(adventures.values()))

# Example usage:
print(archie_adventures())  # Outputs a random adventure of Archie
